#include<bits/stdc++.h>
using namespace std;
vector<int> a;
int n,ant;
int main() {
    cin.tie(0)->sync_with_stdio(0);
	cin >> n;
	for (int i = 1; i <= n; i++) {
        int c;
        cin>>c;
		a.push_back(c);
	}
	sort(a.begin(), a.end());
	for(int i=1;i<=n-1;i++){
		int b=a[0]+a[1];
		ant+=b;
		a.erase(a.begin(),a.begin()+2);
		for(int j=0;j<=a.size();j++){
			if(j==a.size()){
				a.push_back(b);
				break;
			}
			if(a[j]>b){
				a.insert(a.begin()+j,b);
				break;
			}
		}
	}
	cout<<ant;
}
